import { 
  ArrowRightCircle, 
  ArrowLeftCircle, 
  Sparkles, 
  FileText, 
  Globe, 
  Filter, 
  Wrench, 
  GitMerge, 
  StickyNote,
  Blocks
} from 'lucide-react';

const nodeConfig = [
  { type: 'customInput', label: 'Input', color: 'var(--accent-cyan)', icon: ArrowRightCircle },
  { type: 'customOutput', label: 'Output', color: 'var(--accent-emerald)', icon: ArrowLeftCircle },
  { type: 'llm', label: 'LLM', color: 'var(--accent-violet)', icon: Sparkles },
  { type: 'text', label: 'Text', color: 'var(--accent-amber)', icon: FileText },
  { type: 'api', label: 'API Call', color: 'var(--accent-blue)', icon: Globe },
  { type: 'filter', label: 'Filter', color: 'var(--accent-rose)', icon: Filter },
  { type: 'transform', label: 'Transform', color: 'var(--accent-violet)', icon: Wrench },
  { type: 'merge', label: 'Merge', color: 'var(--accent-emerald)', icon: GitMerge },
  { type: 'note', label: 'Note', color: 'var(--accent-amber)', icon: StickyNote },
];

export const LeftSidebar = () => {
  return (
    <div
      style={{
        width: '260px',
        background: 'var(--bg-surface)',
        borderRight: '1px solid var(--border-subtle)',
        display: 'flex',
        flexDirection: 'column',
        height: 'calc(100vh - 56px)',
        zIndex: 10,
      }}
    >
      <div style={{ padding: '20px 16px', borderBottom: '1px solid var(--border-subtle)' }}>
        <div style={{ fontSize: '11px', fontWeight: 600, color: 'var(--text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: '12px' }}>
          Components
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
          {nodeConfig.map((n) => {
            const IconComponent = n.icon;
            return (
              <div 
                key={n.type}
                draggable
                onDragStart={(e) => {
                  e.dataTransfer.setData('application/reactflow', JSON.stringify({ nodeType: n.type }));
                  e.dataTransfer.effectAllowed = 'move';
                }}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '10px',
                  padding: '10px 12px',
                  background: 'var(--bg-app)',
                  border: '1px solid var(--border-subtle)',
                  borderRadius: '6px',
                  cursor: 'grab',
                  color: 'var(--text-secondary)',
                  transition: 'all 0.2s',
                  userSelect: 'none',
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.borderColor = n.color;
                  e.currentTarget.style.color = 'var(--text-primary)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.borderColor = 'var(--border-subtle)';
                  e.currentTarget.style.color = 'var(--text-secondary)';
                }}
              >
                <div style={{ color: n.color, display: 'flex' }}>
                  <IconComponent size={16} />
                </div>
                <span style={{ fontSize: '13px', fontWeight: 500 }}>{n.label}</span>
              </div>
            );
          })}
        </div>
      </div>

      <div style={{ flex: 1 }} />

      <div style={{ padding: '16px', borderTop: '1px solid var(--border-subtle)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', color: 'var(--text-tertiary)' }}>
          <Blocks size={16} />
          <span style={{ fontSize: '12px', fontWeight: 500 }}>VectorShift Enterprise</span>
        </div>
      </div>
    </div>
  );
};
